ValidationRule.errorConditionFormula:
AND(
    NOT(
     CONTAINS(
     LOWER($Profile.Name),
     "admin")),
    NOT(ISPICKVAL(PendencyType__c, 'Validação')),
    OR(
        /* Caso 1: Usuário CRN editando "Resposta da Solicitação" em registro criado por ele mesmo */
        AND(
            $Profile.Name = "CRN",
            CreatedBy.Profile.Name = "CRN", 
            ISCHANGED(CommentResponse__c)
        ),

        /* Caso 2: Usuário 5A editando "Resposta da Solicitação" em registro criado por ele ou Integração QuintoAndar */
        AND(
            $Profile.Name <> "CRN",
            CreatedBy.Profile.Name <> "CRN",
            ISCHANGED(CommentResponse__c)
        ),

        /* Caso 3: Usuário CRN editando "Solicitação" em registro não criado por ele */
        AND(
            $Profile.Name = "CRN",
            CreatedBy.Profile.Name <> "CRN",
            ISCHANGED(Comments__c)
        ),

        /* Caso 4: Usuário 5A editando "Solicitação" em registro criado por CRN */
        AND(
            $Profile.Name <> "CRN",
            CreatedBy.Profile.Name = "CRN",
            ISCHANGED(Comments__c)
        )
    )
)
